# utils/data_utils.pyimport datetimeimport osimport pandas as pdimport numpy as npimport streamlit as stfrom sqlalchemy import create_engine, textfrom config import SCORING_PATH, MOIS_L, JOURS, COUNTRY_MAPPINGEDA_SAMPLE_PATH = os.path.join(os.path.dirname(os.path.dirname(__file__)),                                "data", "eda_sample.csv")def format_heure(valeur):    if pd.isnull(valeur):        return None    if isinstance(valeur, datetime.time):        return valeur.hour    try:        s = str(valeur).strip()        if ":" in s:            return int(s.split(":")[0])        v = int(float(s))        if v == 2400:            v = 0        return int(f"{v:04d}"[:2])    except (ValueError, TypeError):        return Nonedef _get_engine():    """Retourne un moteur SQLAlchemy vers Supabase (pooler)."""    database_url = st.secrets["DATABASE_URL"]    return create_engine(database_url)@st.cache_data(ttl=3600, show_spinner=False)def load_dataset(sample_size: int = None) -> pd.DataFrame:    """    Charge les données depuis Supabase.    - sample_size = None : charge TOUS les vols.    - sample_size = entier : charge un échantillon aléatoire.    """    engine = _get_engine()    with engine.connect() as conn:        # Lecture des tables auxiliaires (toujours complètes)        aeroports = pd.read_sql_query("SELECT * FROM aeroports", conn)        compagnies = pd.read_sql_query("SELECT * FROM compagnies", conn)        # Lecture des vols (échantillon ou total)        if sample_size:            query = f"SELECT * FROM vols ORDER BY RANDOM() LIMIT {sample_size}"        else:            query = "SELECT * FROM vols"        vols_raw = pd.read_sql_query(text(query), conn)    return _build_dataframe(vols_raw, aeroports, compagnies)@st.cache_data(ttl=3600, show_spinner=False)def load_eda_sample() -> pd.DataFrame:    """    Pour l'EDA : utilise un CSV pré-calculé s'il existe,    sinon charge un échantillon aléatoire (3000 vols).    """    if os.path.exists(EDA_SAMPLE_PATH):        df = pd.read_csv(EDA_SAMPLE_PATH, low_memory=False)        for col in ["CRENEAU","SEGMENT_DIST","NOM_MOIS","NOM_JOUR"]:            if col in df.columns:                df[col] = df[col].astype(str)        if "DATE" in df.columns:            df["DATE"] = pd.to_datetime(df["DATE"], errors="coerce")        return df    else:        # Génération à la volée        return load_dataset(sample_size=3000)def _build_dataframe(vols_raw: pd.DataFrame,                     aeroports: pd.DataFrame,                     compagnies: pd.DataFrame) -> pd.DataFrame:    """    Pipeline de transformation – identique à votre version originale,    mais adapté pour fonctionner avec n'importe quelle source (SQLite ou Postgres).    """    # ── Pays codes → noms complets ────────────────────────────    aeroports = aeroports.copy()    aeroports["PAYS"] = aeroports["PAYS"].map(COUNTRY_MAPPING).fillna(aeroports["PAYS"])    aeroports = aeroports.drop_duplicates(subset="CODE IATA", keep="first")    # ── Suppression colonnes inutiles ─────────────────────────    var_to_drop = [        "HEURE D'ARRIVEE","ATTERRISSAGE",        "TEMPS DE DEPLACEMENT A TERRE A L'ATTERRISSAGE",        "TEMPS PASSE","TEMPS DE VOL","DETOURNEMENT","ANNULATION",        "RETARD SYSTEM","RETARD SECURITE","RETARD COMPAGNIE",        "RETARD AVION","RETARD METEO","RAISON D'ANNULATION",        "NIVEAU DE SECURITE","DECOLLAGE","VOL","CODE AVION","IDENTIFIANT",    ]    vols_raw = vols_raw.drop(columns=var_to_drop, errors="ignore")    # ── Formatage des heures ──────────────────────────────────    for col in ["DEPART PROGRAMME","ARRIVEE PROGRAMMEE","HEURE DE DEPART"]:        if col in vols_raw.columns:            vols_raw[col] = vols_raw[col].apply(format_heure)    # ── Date ──────────────────────────────────────────────────    if "DATE" in vols_raw.columns:        # Détection automatique du format        parsed = None        for fmt in ["%d/%m/%Y","%Y-%m-%d","%d-%m-%Y","%m/%d/%Y"]:            candidate = pd.to_datetime(vols_raw["DATE"], format=fmt, errors="coerce")            if candidate.notna().mean() > 0.5:                parsed = candidate                break        vols_raw["DATE"] = parsed if parsed is not None else pd.NaT    vols_raw["JOUR_SEM"] = vols_raw["DATE"].dt.weekday    vols_raw["mois"]     = vols_raw["DATE"].dt.month    vols_raw["annee"]    = vols_raw["DATE"].dt.year    # ── Fusion compagnies ─────────────────────────────────────    df = vols_raw.merge(compagnies, left_on="COMPAGNIE AERIENNE",                        right_on="CODE", how="left")    df.rename(columns={"COMPAGNIE":"NOM_COMPAGNIE"}, inplace=True)    df.drop(columns=["CODE"], errors="ignore", inplace=True)    # ── Fusion aéroport départ ────────────────────────────────    ap_dep = aeroports.rename(columns={        "CODE IATA":"AEROPORT DEPART","NOM":"NOM_AP_DEP",        "LIEU":"VILLE_DEP","PAYS":"PAYS_DEP",        "LONGITUDE":"LON_DEP","LATITUDE":"LAT_DEP","HAUTEUR":"HAUTEUR_DEP",        "PRIX RETARD PREMIERE 10 MINUTES":"COUT_10_DEP",        "PRIS RETARD POUR CHAQUE MINUTE APRES 10 MINUTES":"COUT_SUP_DEP",    })    df = df.merge(ap_dep, on="AEROPORT DEPART", how="left")    # ── Fusion aéroport arrivée ───────────────────────────────    ap_arr = aeroports.rename(columns={        "CODE IATA":"AEROPORT ARRIVEE","NOM":"NOM_AP_ARR",        "LIEU":"VILLE_ARR","PAYS":"PAYS_ARR",        "LONGITUDE":"LON_ARR","LATITUDE":"LAT_ARR","HAUTEUR":"HAUTEUR_ARR",        "PRIX RETARD PREMIERE 10 MINUTES":"COUT_10_ARR",        "PRIS RETARD POUR CHAQUE MINUTE APRES 10 MINUTES":"COUT_SUP_ARR",    })    df = df.merge(ap_arr, on="AEROPORT ARRIVEE", how="left")    # ── Renommage final ───────────────────────────────────────    df.rename(columns={        "RETARD A L'ARRIVEE"               : "RETARD_ARRIVEE",        "RETART DE DEPART"                 : "RETARD_DEPART",        "TEMPS DE DEPLACEMENT A TERRE AU DECOLLAGE": "TAXI_TIME",        "TEMPS PROGRAMME"                  : "TEMPS_VOL",        "DEPART PROGRAMME"                 : "DEPART_PROG",        "HEURE DE DEPART"                  : "HEURE_DEP",        "ARRIVEE PROGRAMMEE"               : "ARRIVEE_PROG",        "COMPAGNIE AERIENNE"               : "COMPAGNIE",        "AEROPORT DEPART"                  : "AP_DEP",        "AEROPORT ARRIVEE"                 : "AP_ARR",        "DISTANCE"                         : "DISTANCE",    }, inplace=True)    # ── Typage numérique ──────────────────────────────────────    for c in ["RETARD_ARRIVEE","RETARD_DEPART","TAXI_TIME","TEMPS_VOL",              "DISTANCE","COUT_10_DEP","COUT_SUP_DEP","COUT_10_ARR","COUT_SUP_ARR",              "LON_DEP","LAT_DEP","HAUTEUR_DEP","LON_ARR","LAT_ARR","HAUTEUR_ARR"]:        if c in df.columns:            df[c] = pd.to_numeric(df[c], errors="coerce")    # ── Variables cibles et dérivées ──────────────────────────    df["RETARD_BIN"]    = (df["RETARD_ARRIVEE"] > 15).astype("Int8")    df["RETARD_SEVERE"] = (df["RETARD_ARRIVEE"] > 60).astype("Int8")    df["COUT_TOTAL"] = sum(        df.get(c, pd.Series(0, index=df.index)).fillna(0)        for c in ["COUT_10_DEP","COUT_SUP_DEP","COUT_10_ARR","COUT_SUP_ARR"]    )    # ── Heure de départ (format numérique) ─────────────────────    if "HEURE_DEP" in df.columns:        raw = df["HEURE_DEP"].astype(str)        if raw.str.contains(":").any():            df["HEURE_DEP_H"] = pd.to_numeric(raw.str.split(":").str[0], errors="coerce")        else:            df["HEURE_DEP_H"] = pd.to_numeric(raw, errors="coerce") // 100    else:        df["HEURE_DEP_H"] = np.nan    # ── Année, mois, jour de la semaine ───────────────────────    if "DATE" in df.columns:        df["ANNEE"]    = df["DATE"].dt.year        df["MOIS"]     = df["DATE"].dt.month        df["JOUR_SEM"] = df["DATE"].dt.dayofweek    else:        df["ANNEE"]    = df.get("annee", np.nan)        df["MOIS"]     = df.get("mois",  np.nan)        df["JOUR_SEM"] = df.get("JOUR_SEM", np.nan)    # ── Libellés mois et jour ─────────────────────────────────    df["NOM_MOIS"] = df["MOIS"].apply(        lambda x: MOIS_L[int(x)-1] if pd.notna(x) and 1<=int(x)<=12 else "?")    df["NOM_JOUR"] = df["JOUR_SEM"].apply(        lambda x: JOURS[int(x)] if pd.notna(x) and 0<=int(x)<=6 else "?")    # ── Créneau horaire et segment distance ───────────────────    df["CRENEAU"] = pd.cut(        df["HEURE_DEP_H"],        bins=[-1,5,8,11,14,17,20,24],        labels=["Nuit (0-5h)","Tôt matin (6-8h)","Matin (9-11h)",                "Midi (12-14h)","Après-midi (15-17h)","Soirée (18-20h)",                "Nuit tardive (21-24h)"],    )    df["SEGMENT_DIST"] = pd.cut(        df["DISTANCE"],        bins=[0,500,1500,3000,np.inf],        labels=["Court (<500km)","Moyen (500-1500km)",                "Long (1500-3000km)","Ultra-long (>3000km)"],    )    # ── Nettoyage final ───────────────────────────────────────    df = df.dropna(subset=["RETARD_BIN"]).reset_index(drop=True)    return df# ══════════════════════════════════════════════════════════════# Fonctions utilitaires (inchangées)# ══════════════════════════════════════════════════════════════@st.cache_data(ttl=3600, show_spinner=False)def load_scoring() -> pd.DataFrame:    try:        df = pd.read_csv(SCORING_PATH)        if "PROBA_RETARD" not in df.columns:            df["PROBA_RETARD"] = np.random.uniform(0, 1, len(df))        return df.sort_values("PROBA_RETARD", ascending=False).reset_index(drop=True)    except FileNotFoundError:        return pd.DataFrame()def get_kpis(df: pd.DataFrame) -> dict:    return {        "total_vols"   : len(df),        "taux_retard"  : float(df["RETARD_BIN"].mean() * 100),        "nb_retardes"  : int(df["RETARD_BIN"].sum()),        "retard_moyen" : float(df.loc[df["RETARD_BIN"]==1, "RETARD_ARRIVEE"].mean()),        "nb_compagnies": int(df["NOM_COMPAGNIE"].nunique()) if "NOM_COMPAGNIE" in df.columns else 0,        "nb_pays"      : int(df["PAYS_DEP"].nunique()) if "PAYS_DEP" in df.columns else 0,        "cout_moyen"   : float(df["COUT_TOTAL"].mean()),        "pct_severe"   : float(df["RETARD_SEVERE"].mean() * 100),    }def get_risk_label(proba: float) -> tuple:    if proba >= 0.75: return "🔴 Critique", "critical"    elif proba >= 0.50: return "🟠 Élevé",   "high"    elif proba >= 0.25: return "🟡 Modéré",  "moderate"    else:               return "🟢 Faible",  "low"def get_risk_color(proba: float) -> str:    if proba >= 0.75: return "#E74C3C"    elif proba >= 0.50: return "#E67E22"    elif proba >= 0.25: return "#F39C12"    else:               return "#2ECC71"# force rebuild
